def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0.25:
            priorities[i] = 50 * (1 - ratio) ** 3
        elif 0.25 <= ratio < 0.5:
            score = 0
            for k in range(1, int(capacity) + 1):
                if capacity % k == 0:
                    score += k / (k + 1)
            priorities[i] = score / (capacity + 1) + 10 * ratio
        elif 0.5 <= ratio <= 1:
            priorities[i] = np.log1p(ratio) * 10 + sum([(-1) ** n / (n + 1) for n in range(5)])
        else:
            penalty = 0
            integer_part = int(ratio)
            fractional_part = ratio - integer_part
            for j in range(1, integer_part + 1):
                if integer_part % j == 0:
                    penalty += j ** 1.5
            if fractional_part > 0:
                penalty += fractional_part * 15
                for m in range(1, 4):
                    penalty -= ((-1) ** m) * fractional_part / m
            priorities[i] = penalty + ratio * 25
        if np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = 1e6
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 500)
    for idx in range(len(priorities)):
        if priorities[idx] > 1000:
            priorities[idx] /= 10
    return priorities
